      status: app.status,
      coverLetter: app.coverLetter,
      createdAt: app.createdAt,
      updatedAt: app.updatedAt,
      adminNotes: app.adminNotes,
      aiAnalysis: app.aiAnalysis,
      applicant: app.applicant,
      job: app.job
    }));

    res.json({
      success: true,
      data: transformedApplications
    });
