router.post('/apply/:jobId', authenticateToken, async (req, res) => {
  try {
    const { jobId } = req.params;
    const { coverLetter } = req.body;
    const userId = req.user._id;

    // Check if job exists
    const job = await JobRole.findById(jobId);
    if (!job) {
      return res.status(404).json({
        success: false,
        error: 'Job not found'
      });
    }

    // Check if already applied
    const existingApplication = await JobApplication.findOne({
      applicant: userId,
      job: jobId
    });

    if (existingApplication) {
      return res.status(400).json({
        success: false,
        error: 'You have already applied to this job'
      });
    }

    // Create application
    const application = new JobApplication({
      applicant: userId,
      job: jobId,
      coverLetter,
      status: 'pending'
    });

    await application.save();

    // Update job application count
    await JobRole.findByIdAndUpdate(jobId, {
      $inc: { applications: 1 }
    });

    res.status(201).json({
      success: true,
      data: application
    });
  } catch (error) {
    res.status(500).json({
      success: false,
      error: error.message
    });
  }
});

// Save/unsave a job
router.post('/save-job/:jobId', authenticateToken, async (req, res) => {
  try {
    const { jobId } = req.params;
    const userId = req.user._id;

    // Check if job exists
    const job = await JobRole.findById(jobId);
    if (!job) {
      return res.status(404).json({
        success: false,
        error: 'Job not found'
      });
    }

    // Check if already saved
    const existingSave = await SavedJob.findOne({
      user: userId,
      job: jobId
    });

    if (existingSave) {
      // Unsave
      await SavedJob.deleteOne({ _id: existingSave._id });
      res.json({
        success: true,
        data: { action: 'unsaved' }
      });
    } else {
      // Save
      const savedJob = new SavedJob({
        user: userId,
        job: jobId
      });
      await savedJob.save();
      res.json({
        success: true,
        data: { action: 'saved' }
      });
    }
  } catch (error) {
    res.status(500).json({
      success: false,
      error: error.message
    });
  }
});

// Helper function to get status color
function getStatusColor(status) {
  switch (status.toLowerCase()) {
    case 'pending': return 'blue';
    case 'reviewing': return 'yellow';
    case 'shortlisted': return 'green';
    case 'interview-scheduled': return 'purple';
    case 'rejected': return 'red';
    case 'hired': return 'green';
    default: return 'gray';
  }
}

export default router;

